/**
 * @summary Get benchmark data
 */
export const getGetBenchmarksUrl = (params: GetBenchmarksParams) => {
  const normalizedParams = new URLSearchParams();

  Object.entries(params || {}).forEach(([key, value]) => {
    if (value !== undefined) {
      normalizedParams.append(key, value === null ? "null" : value.toString());
    }
  });

  const stringifiedParams = normalizedParams.toString();

  return stringifiedParams.length > 0
    ? `/api/benchmarks?${stringifiedParams}`
    : `/api/benchmarks`;
};

export const getBenchmarks = async (
  params: GetBenchmarksParams,
  options?: RequestInit,
): Promise<KpiBenchmark[]> => {
  return customFetch<KpiBenchmark[]>(getGetBenchmarksUrl(params), {
    ...options,
    method: "GET",
  });
};

export const getGetBenchmarksQueryKey = (params?: GetBenchmarksParams) => {
  return [`/api/benchmarks`, ...(params ? [params] : [])] as const;
};

export const getGetBenchmarksQueryOptions = <
  TData = Awaited<ReturnType<typeof getBenchmarks>>,
  TError = ErrorType<unknown>,
>(
  params: GetBenchmarksParams,
  options?: {
    query?: UseQueryOptions<
      Awaited<ReturnType<typeof getBenchmarks>>,
      TError,
      TData
    >;
    request?: SecondParameter<typeof customFetch>;
  },
) => {
  const { query: queryOptions, request: requestOptions } = options ?? {};

  const queryKey = queryOptions?.queryKey ?? getGetBenchmarksQueryKey(params);

  const queryFn: QueryFunction<Awaited<ReturnType<typeof getBenchmarks>>> = ({
    signal,
  }) => getBenchmarks(params, { signal, ...requestOptions });

  return { queryKey, queryFn, ...queryOptions } as UseQueryOptions<
    Awaited<ReturnType<typeof getBenchmarks>>,
    TError,
    TData
  > & { queryKey: QueryKey };
};

export type GetBenchmarksQueryResult = NonNullable<
  Awaited<ReturnType<typeof getBenchmarks>>
>;
export type GetBenchmarksQueryError = ErrorType<unknown>;

/**
 * @summary Get benchmark data
 */

export function useGetBenchmarks<
  TData = Awaited<ReturnType<typeof getBenchmarks>>,
  TError = ErrorType<unknown>,
>(
  params: GetBenchmarksParams,
  options?: {
    query?: UseQueryOptions<
      Awaited<ReturnType<typeof getBenchmarks>>,
      TError,
      TData
    >;
    request?: SecondParameter<typeof customFetch>;
  },
): UseQueryResult<TData, TError> & { queryKey: QueryKey } {
  const queryOptions = getGetBenchmarksQueryOptions(params, options);

  const query = useQuery(queryOptions) as UseQueryResult<TData, TError> & {
    queryKey: QueryKey;
  };

  return { ...query, queryKey: queryOptions.queryKey };
}

